class Solution:
    def waysToMakeFair(self, nums):
        n = len(nums)
        count = 0
        for i in range(n):
            remaining = nums[:i] + nums[i + 1:]
            even_sum = sum(remaining[k] for k in range(0, len(remaining), 2))
            odd_sum = sum(remaining[k] for k in range(1, len(remaining), 2))
            if even_sum == odd_sum:
                count += 1
        return count

