class Solution:
    def waysToMakeFair(self, nums):
        n = len(nums)
        total_even = sum(nums[i] for i in range(0, n, 2))
        total_odd = sum(nums[i] for i in range(1, n, 2))
        left_even = left_odd = 0
        count = 0
        for i in range(n):
            right_even = total_even - left_even - (nums[i] if i % 2 == 0 else 0)
            right_odd = total_odd - left_odd - (nums[i] if i % 2 == 1 else 0)
            new_even = left_even + right_odd
            new_odd = left_odd + right_even
            if new_even == new_odd:
                count += 1
            if i % 2 == 0:
                left_even += nums[i]
            else:
                left_odd += nums[i]
        return count

