var waysToMakeFair = function(nums) {
    const n = nums.length;
    let totalEven = 0, totalOdd = 0;
    for (let i = 0; i < n; i++) {
        if (i % 2 === 0) totalEven += nums[i]; else totalOdd += nums[i];
    }
    let leftEven = 0, leftOdd = 0, count = 0;
    for (let i = 0; i < n; i++) {
        const rightEven = totalEven - leftEven - (i % 2 === 0 ? nums[i] : 0);
        const rightOdd = totalOdd - leftOdd - (i % 2 === 1 ? nums[i] : 0);
        const newEven = leftEven + rightOdd;
        const newOdd = leftOdd + rightEven;
        if (newEven === newOdd) count++;
        if (i % 2 === 0) leftEven += nums[i]; else leftOdd += nums[i];
    }
    return count;
};
